	case plans.Delete:
		return "  [red]-[reset]"
	case plans.Forget:
		return " [red].[reset]"
	case plans.CreateThenForget:
		return " [green]+[reset]/[red].[reset]"
	case plans.Read:
		return " [cyan]<=[reset]"
	case plans.Update:
		return "  [yellow]~[reset]"
	case plans.NoOp:
		return "   "
	default:
		return "  ?"
	}
}

