func TestCompactDiffFormatterSorted(t *testing.T) {
	// Test that resources are sorted alphabetically within each action group
	plan := &plans.Plan{
		Changes: &plans.ChangesSrc{
			Resources: []*plans.ResourceInstanceChangeSrc{
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "zebra",
							},
							Key: nil,
						},
					},
					DeposedKey: states.NotDeposed,
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
				},
				{
					Addr: addrs.AbsResourceInstance{
						Module: addrs.RootModuleInstance,
						Resource: addrs.ResourceInstance{
							Resource: addrs.Resource{
								Mode: addrs.ManagedResourceMode,
								Type: "aws_instance",
								Name: "alpha",
							},
							Key: nil,
						},
					},
					DeposedKey: states.NotDeposed,
					ChangeSrc: plans.ChangeSrc{
						Action: plans.Create,
					},
				},
			},
		},
	}

	formatter := &CompactDiffFormatter{}
	got := formatter.Format(plan, nil)

	// The output should have alpha before zebra
	alphaIdx := len("  [green]+[reset] Create:\n  ")
	zebra := "zebra"
	alpha := "alpha"

	if idx := len(got); idx < len(zebra) {
		t.Fatalf("output too short")
	}

	// Find positions of resource names in output
	alphaPos := -1
	zebraPos := -1

	for i := 0; i < len(got)-len(alpha); i++ {
		if got[i:i+len(alpha)] == alpha && i > 20 { // After the header
			alphaPos = i
			break
		}
	}

	for i := 0; i < len(got)-len(zebra); i++ {
		if got[i:i+len(zebra)] == zebra && i > 20 { // After the header
			zebraPos = i
			break
		}
	}

	if alphaPos == -1 || zebraPos == -1 {
		t.Fatalf("could not find resource names in output: %s", got)
	}

	if alphaPos >= zebraPos {
		t.Errorf("resources not sorted: alpha at %d, zebra at %d", alphaPos, zebraPos)
	}
}

func TestFormatActionName(t *testing.T) {
	tests := map[plans.Action]string{
		plans.Create:           "Create",
		plans.Update:           "Update",
		plans.Delete:           "Delete",
		plans.DeleteThenCreate: "Replace (delete then create)",
		plans.CreateThenDelete: "Replace (create then delete)",
		plans.Read:             "Read",
		plans.Forget:           "Forget",
		plans.CreateThenForget: "Forget",
		plans.Renew:            "Renew",
		plans.Open:             "Open",
		plans.Close:            "Close",
	}

	for action, expected := range tests {
		t.Run(string(action), func(t *testing.T) {
			got := formatActionName(action)
			if got != expected {
				t.Errorf("got %q, want %q", got, expected)
			}
		})
	}
}

func TestFormatSummary(t *testing.T) {
	tests := map[string]struct {
		counts map[plans.Action]int
		want   string
	}{
		"single action": {
			counts: map[plans.Action]int{plans.Create: 1},
			want:   "Plan: 1 to add.\n",
		},
		"multiple actions": {
			counts: map[plans.Action]int{
				plans.Create: 2,
				plans.Update: 1,
				plans.Delete: 3,
			},
			want: "Plan: 2 to add, 1 to change, 3 to destroy.\n",
		},
		"replace actions": {
			counts: map[plans.Action]int{
				plans.DeleteThenCreate: 1,
				plans.Create:           1,
			},
			want: "Plan: 1 to add, 1 to replace.\n",
		},
		"empty counts": {
			counts: map[plans.Action]int{},
			want:   "No changes.\n",
		},
		"zero counts": {
			counts: map[plans.Action]int{
				plans.Create: 0,
				plans.Update: 0,
			},
			want: "No changes.\n",
		},
	}

	for name, tc := range tests {
		t.Run(name, func(t *testing.T) {
			got := formatSummary(tc.counts)
			if got != tc.want {
