		})
	}
}

func TestFormatSummary(t *testing.T) {
	tests := map[string]struct {
		counts map[plans.Action]int
		want   string
	}{
		"single action": {
			counts: map[plans.Action]int{plans.Create: 1},
			want:   "Plan: 1 to add.\n",
		},
		"multiple actions": {
			counts: map[plans.Action]int{
				plans.Create: 2,
				plans.Update: 1,
				plans.Delete: 3,
			},
			want: "Plan: 2 to add, 1 to change, 3 to destroy.\n",
		},
		"replace actions": {
			counts: map[plans.Action]int{
				plans.DeleteThenCreate: 1,
				plans.Create:           1,
			},
			want: "Plan: 1 to add, 1 to replace.\n",
		},
		"empty counts": {
			counts: map[plans.Action]int{},
			want:   "No changes.\n",
		},
		"zero counts": {
			counts: map[plans.Action]int{
				plans.Create: 0,
				plans.Update: 0,
			},
			want: "No changes.\n",
		},
	}

	for name, tc := range tests {
		t.Run(name, func(t *testing.T) {
			got := formatSummary(tc.counts)
			if got != tc.want {
				t.Errorf("got %q, want %q", got, tc.want)
			}
		})
	}
}

