package format

import (
	"fmt"
	"sort"
	"strings"

	"github.com/hashicorp/terraform/internal/addrs"
	"github.com/hashicorp/terraform/internal/plans"
	"github.com/hashicorp/terraform/internal/schemarepo"
	"github.com/hashicorp/terraform/internal/states"
)

// CompactDiffFormatter produces a condensed, summary-style diff output,
// showing only resource-level changes without attribute-level detail.
type CompactDiffFormatter struct{}

// Format produces a compact diff summary of the given plan.
// It outputs one line per resource change grouped by action type and
// includes summary counts at the end.
func (f *CompactDiffFormatter) Format(plan *plans.Plan, schemas *schemarepo.Schemas) string {
	if plan == nil || plan.Changes == nil {
		return ""
	}

	// Group changes by action type
	changes := make(map[plans.Action][]*plans.ResourceInstanceChangeSrc)

	for _, rc := range plan.Changes.Resources {
		// Skip deposed resources
		if rc.DeposedKey != states.NotDeposed {
			continue
		}

		// Skip no-op changes
		if rc.Action == plans.NoOp {
			continue
		}

		changes[rc.Action] = append(changes[rc.Action], rc)
	}

	// Define the order of action types to display
	actionOrder := []plans.Action{
		plans.Create,
		plans.Update,
		plans.Delete,
		plans.DeleteThenCreate,
		plans.CreateThenDelete,
		plans.CreateThenForget,
		plans.Forget,
		plans.Read,
		plans.Renew,
		plans.Open,
		plans.Close,
	}

	var result strings.Builder

	// Count totals for summary
	actionCounts := make(map[plans.Action]int)

	// Process changes in defined order
	for _, action := range actionOrder {
		resources, exists := changes[action]
		if !exists || len(resources) == 0 {
			continue
		}

		// Sort resources by address for consistent output
		sort.Slice(resources, func(i, j int) bool {
			return resources[i].Addr.String() < resources[j].Addr.String()
		})

		// Write action group header
		actionSymbol := DiffActionSymbol(action)
		actionName := formatActionName(action)
		result.WriteString(fmt.Sprintf("\n%s %s:\n", actionSymbol, actionName))

		// Write each resource in this group
		for _, rc := range resources {
			result.WriteString(fmt.Sprintf("  %s\n", rc.Addr.String()))
			actionCounts[action]++
		}
	}

	// Write summary
	if len(plan.Changes.Resources) > 0 {
		result.WriteString("\n")
		result.WriteString(formatSummary(actionCounts))
	}

	return result.String()
}

// formatActionName returns a human-readable name for an action.
func formatActionName(action plans.Action) string {
	switch action {
	case plans.Create:
		return "Create"
	case plans.Read:
		return "Read"
	case plans.Update:
		return "Update"
	case plans.Delete:
		return "Delete"
	case plans.DeleteThenCreate:
		return "Replace (delete then create)"
	case plans.CreateThenDelete:
		return "Replace (create then delete)"
	case plans.CreateThenForget:
		return "Forget"
	case plans.Forget:
		return "Forget"
	case plans.Renew:
		return "Renew"
	case plans.Open:
		return "Open"
	case plans.Close:
		return "Close"
	default:
		return "Unknown"
	}
}

// formatSummary produces a summary line showing counts by action type.
func formatSummary(counts map[plans.Action]int) string {
	var parts []string

	// Build summary in a consistent order
	summaryOrder := []struct {
		action plans.Action
		label  string
	}{
		{plans.Create, "add"},
		{plans.Update, "change"},
		{plans.Delete, "destroy"},
		{plans.DeleteThenCreate, "replace"},
		{plans.CreateThenDelete, "replace"},
		{plans.CreateThenForget, "forget"},
		{plans.Forget, "forget"},
		{plans.Read, "read"},
		{plans.Renew, "renew"},
		{plans.Open, "open"},
		{plans.Close, "close"},
	}

	for _, item := range summaryOrder {
		if count, exists := counts[item.action]; exists && count > 0 {
			parts = append(parts, fmt.Sprintf("%d to %s", count, item.label))
		}
	}

	if len(parts) == 0 {
		return "No changes."
	}

	return fmt.Sprintf("Plan: %s.\n", strings.Join(parts, ", "))
}

